import {
  Table,
  TableBody,
  TableCaption,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table"
import { cn } from "@/lib/utils"

import React from 'react'

interface Column<T> {
  header: string;
  accessor?: keyof T;
  cell: (row: T, index: number) => React.ReactNode;
}

interface DataTableProps<T> {
  columns: Column<T>[];
  data?: T[];
  rowKey: (row: T, index: number) => React.Key;
  tableClassName?: string;
  headerRowClassName?: string;
  headerClassName?: string;
  headerCellClassName?: string;
  bodyRowClassName?: string;
  bodyCellClassName?: string;
}

const DataTable = <T,>({ columns, data, rowKey, tableClassName, headerRowClassName, headerClassName, headerCellClassName, bodyRowClassName, bodyCellClassName }: DataTableProps<T>) => {
  return (
    <Table className={cn('custom-scrollbar', tableClassName)}>
      <TableHeader className={headerClassName}>
        <TableRow className={cn('hover:bg-transparent!'
          , headerRowClassName)}>
          {columns.map((column, i) => (
            <TableHead key={i} className={cn('bg-dark-400 text-purple-100 py-4 first:pl-5 last:pr-5')}>
              {column.header}
            </TableHead>
          ))}
        </TableRow>
      </TableHeader>
      <TableBody>
        {data?.map((row, rowIndex) => (
          <TableRow key={rowKey(row, rowIndex)} className={cn('overflow-hidden rounded-lg border-b border-purple-100/5 hover:bg-dark-400/30! relative',
            bodyRowClassName)}>
            {columns.map((column, columnIndex) => (
              <TableCell key={columnIndex} className={cn('py-4 first:pl-5 last:pr-5')}>
                {column.cell(row, rowIndex)}
              </TableCell>
            ))}
          </TableRow>
        ))}
      </TableBody>
    </Table>
  )
}

export default DataTable

'use client';

import React, { useState, useEffect } from 'react';
import { Star } from 'lucide-react';

export default function WatchlistButton({ coinId }: { coinId: string }) {
    const [isStarred, setIsStarred] = useState(false);

    useEffect(() => {
        const saved = localStorage.getItem('zync_watchlist');
        if (saved) {
            try {
                const parsed = JSON.parse(saved);
                if (Array.isArray(parsed) && parsed.includes(coinId)) {
                    setTimeout(() => setIsStarred(true), 0);
                }
            } catch (e) {
                // ignore
            }
        }
    }, [coinId]);

    const toggleStar = () => {
        const saved = localStorage.getItem('zync_watchlist');
        let parsed: string[] = [];
        if (saved) {
            try {
                parsed = JSON.parse(saved);
                if (!Array.isArray(parsed)) parsed = [];
            } catch (e) {
                parsed = [];
            }
        }

        if (isStarred) {
            parsed = parsed.filter(id => id !== coinId);
        } else {
            if (!parsed.includes(coinId)) {
                parsed.push(coinId);
            }
        }

        localStorage.setItem('zync_watchlist', JSON.stringify(parsed));
        setIsStarred(!isStarred);
    };

    return (
        <button
            onClick={toggleStar}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg border transition-colors ${isStarred
                ? 'bg-yellow-400/10 border-yellow-400/30 text-yellow-400 hover:bg-yellow-400/20'
                : 'bg-card-bg border-border-color text-text-primary hover:bg-bg-secondary hover:border-text-muted/30'
                }`}
        >
            <Star size={18} className={isStarred ? 'fill-yellow-400' : ''} />
            <span className="font-medium">{isStarred ? 'Saved to Watchlist' : 'Add to Watchlist'}</span>
        </button>
    );
}

const fs = require('fs');
let content = fs.readFileSync('eslint_report.json', 'utf8');
if (content.charCodeAt(0) === 0xFEFF) {
    content = content.slice(1);
}
const results = JSON.parse(content);
const out = [];
results.forEach(r => {
    r.messages.forEach(m => {
        if (m.severity === 2) {
            out.push(r.filePath + ':' + m.line + ':' + m.column + ' - ' + m.message);
        }
    });
});
fs.writeFileSync('parsed_errs.txt', out.join('\n'));
